import{_ as a,o as d,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"虚拟电厂入市与电力交易 AI 收入——2026 年进展","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"电力新能源/电力市场/_深化_2026-06-16_虚拟电厂入市与电力交易AI.md","filePath":"电力新能源/电力市场/_深化_2026-06-16_虚拟电厂入市与电力交易AI.md","lastUpdated":1782226922000}'),o={name:"电力新能源/电力市场/_深化_2026-06-16_虚拟电厂入市与电力交易AI.md"};function l(i,t,h,n,s,P){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="虚拟电厂入市与电力交易-ai-收入——2026-年进展" tabindex="-1">虚拟电厂入市与电力交易 AI 收入——2026 年进展 <a class="header-anchor" href="#虚拟电厂入市与电力交易-ai-收入——2026-年进展" aria-label="Permalink to &quot;虚拟电厂入市与电力交易 AI 收入——2026 年进展&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>虚拟电厂（VPP）正在从示范走向入市交易。广东 2025 年首批 51 家 VPP 入市，可调度容量最低 1MW。26 省出台省级需求响应/虚拟电厂政策。全国 VPP 聚合容量约 51GW（2023 年数据）。电力交易 AI 尚处起步阶段，参与现货市场预测和报量报价但仍以人工审核为主。为恒智能等企业推出 AI Agent 商业化产品，VPP + AI 交易年增收约 8%-15%。</p><h2 id="虚拟电厂入市进展" tabindex="-1">虚拟电厂入市进展 <a class="header-anchor" href="#虚拟电厂入市进展" aria-label="Permalink to &quot;虚拟电厂入市进展&quot;">​</a></h2><h3 id="广东——全国-vpp-入市先行者" tabindex="-1">广东——全国 VPP 入市先行者 <a class="header-anchor" href="#广东——全国-vpp-入市先行者" aria-label="Permalink to &quot;广东——全国 VPP 入市先行者&quot;">​</a></h3><ul><li><strong>2025 年 5 月</strong>：广东首批 51 家虚拟电厂正式进入电力市场交易</li><li><strong>可调度容量要求</strong>：最低 1MW</li><li><strong>参与方式</strong>：需求响应 + 辅助服务</li><li><strong>交易品种</strong>：调频、备用、需求侧响应</li><li><strong>收益模型</strong>：响应补贴 + 辅助服务收入 + 现货套利</li><li><strong>意义</strong>：中国 VPP 从&quot;示范&quot;走向&quot;入市交易&quot;的标志性事件</li></ul><h3 id="全国政策覆盖" tabindex="-1">全国政策覆盖 <a class="header-anchor" href="#全国政策覆盖" aria-label="Permalink to &quot;全国政策覆盖&quot;">​</a></h3><ul><li><strong>26 省</strong>：出台了省级需求响应/虚拟电厂相关政策</li><li><strong>国家层面</strong>：发改委/能源局持续推动 VPP 纳入电力市场交易体系</li><li><strong>标准制定</strong>：2026 年 VPP 入市交易规则正在完善中</li></ul><h3 id="聚合容量" tabindex="-1">聚合容量 <a class="header-anchor" href="#聚合容量" aria-label="Permalink to &quot;聚合容量&quot;">​</a></h3><p>截至 2023 年底：全国 VPP 聚合容量约 51GW（包括工业/商业/充电桩/用户侧储能等柔性资源）</p><h2 id="电力交易-ai——早期但进展快" tabindex="-1">电力交易 AI——早期但进展快 <a class="header-anchor" href="#电力交易-ai——早期但进展快" aria-label="Permalink to &quot;电力交易 AI——早期但进展快&quot;">​</a></h2><h3 id="当前状态" tabindex="-1">当前状态 <a class="header-anchor" href="#当前状态" aria-label="Permalink to &quot;当前状态&quot;">​</a></h3><p><strong>核心结论：电力交易 AI 在现货市场预测方面已有一定应用，但在交易决策中仍以人工审核为主，尚未实现全自主 AI 交易。</strong></p><table tabindex="0"><thead><tr><th>应用场景</th><th>AI 成熟度</th><th>说明</th></tr></thead><tbody><tr><td>现货价格预测</td><td>✅ 较成熟</td><td>机器学习预测次日分时电价</td></tr><tr><td>新能源出力预测</td><td>✅ 较成熟</td><td>风光功率预测</td></tr><tr><td>报量报价辅助</td><td>🟡 半自动</td><td>AI 生成建议→人工审核→提交</td></tr><tr><td>交易策略优化</td><td>🟡 初创</td><td>多家初创企业+头部玩家布局</td></tr><tr><td>全自主 AI 交易</td><td>❌ 未落地</td><td>监管+风险原因</td></tr></tbody></table><h3 id="ai-预测价值" tabindex="-1">AI 预测价值 <a class="header-anchor" href="#ai-预测价值" aria-label="Permalink to &quot;AI 预测价值&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>不采用 AI</th><th>采用 AI</th><th>年增收</th></tr></thead><tbody><tr><td>现货套利</td><td>基准</td><td>+5%-8%</td><td>约 5-8 万/10MWh</td></tr><tr><td>辅助服务</td><td>基准</td><td>+10%-15%</td><td>约 10-15 万/10MWh</td></tr><tr><td>综合优化</td><td>基准</td><td>+15%-25%</td><td>约 15-25 万/10MWh</td></tr></tbody></table><h3 id="典型企业" tabindex="-1">典型企业 <a class="header-anchor" href="#典型企业" aria-label="Permalink to &quot;典型企业&quot;">​</a></h3><table tabindex="0"><thead><tr><th>企业</th><th>产品</th><th>进展</th></tr></thead><tbody><tr><td>为恒智能</td><td>WHES OS AI Agent</td><td>实测年收益提升 8%-15%，调度成本下降 20%</td></tr><tr><td>国能日新</td><td>功率预测系统</td><td>电力交易辅助决策</td></tr><tr><td>远景能源</td><td>EnOS AI</td><td>交易策略优化</td></tr><tr><td>阿里云</td><td>电力 AI</td><td>电网调度优化</td></tr><tr><td>南网</td><td>&quot;大瓦特&quot; AI</td><td>调度辅助（已在 700+ 场景部署）</td></tr></tbody></table><h2 id="vpp-ai-商业模式比较" tabindex="-1">VPP + AI 商业模式比较 <a class="header-anchor" href="#vpp-ai-商业模式比较" aria-label="Permalink to &quot;VPP + AI 商业模式比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>价值主张</th><th>竞品</th><th>预估市占率</th></tr></thead><tbody><tr><td>AI 聚合调控</td><td>为恒智能、远景</td><td>~15%</td></tr><tr><td>需求侧响应</td><td>国能日新、恒实科技</td><td>~30%</td></tr><tr><td>售电侧优化</td><td>阿里云、腾讯云</td><td>~20%</td></tr><tr><td>交易赋能</td><td>各头部玩家</td><td>~25%</td></tr></tbody></table><p><strong>VPP + AI 交易年增收约 8%-15%</strong>，核心价值在于提升柔性资源的调度效率和交易精度。</p><h2 id="个体户参与现货市场" tabindex="-1">个体户参与现货市场 <a class="header-anchor" href="#个体户参与现货市场" aria-label="Permalink to &quot;个体户参与现货市场&quot;">​</a></h2><p><strong>现状：个体户直接参与现货市场的门槛仍然很高。</strong> 主要障碍：</p><ol><li><strong>技术门槛</strong>：需具备交易员能力，报价/报量/风险控制专业要求高</li><li><strong>门槛要求</strong>：最小申报单元 1-10MW（各地不同）</li><li><strong>行政成本</strong>：注册/结算/考核手续复杂</li><li><strong>偏差考核风险</strong>：预测偏差导致罚款</li></ol><p><strong>通过 VPP 聚合参与是当前最优路径</strong>：VPP 运营商聚合 1MW+ 灵活资源后统一入市，降低个体门槛，分摊管理成本。</p><h2 id="投资逻辑" tabindex="-1">投资逻辑 <a class="header-anchor" href="#投资逻辑" aria-label="Permalink to &quot;投资逻辑&quot;">​</a></h2><ol><li><strong>VPP 入市从广东开始扩散</strong>，2027 年预计全国多省跟进</li><li><strong>AI 交易需求爆发拐点在 2027-2028 年</strong>：配额收紧+现货市场扩大驱动</li><li><strong>VPP + AI 组合最具商业价值</strong>：聚合资源 + 智能调度 + 最优交易</li><li><strong>个体户暂不建议直接入市</strong>，通过 VPP 聚合参与更高效</li></ol><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li>VPP 入市规则尚未统一，各省差异大</li><li>AI 交易决策仍受监管限制，全自主交易短期难放开</li><li>VPP 聚合商良莠不齐，选择成本高</li><li>电力现货市场覆盖范围有限（目前试点省份少）</li><li>偏差考核风险可能侵蚀套利收益</li></ol><hr><p><em>来源：国家能源局、广东电力交易中心、经济观察网、远景能源、为恒智能、光大证券</em><em>更新：2026-06-16</em></p>',31)])])}const g=a(o,[["render",l]]);export{_ as __pageData,g as default};
